{
  "mode": "method",
  "tests": [
    {
      "name": "basic_infusion",
      "input": ["track1.mp3", 30],
      "output": {"intensity": 30, "listenability": true},
      "args": ["track1.mp3", 30],
      "notes": "Tests basic functionality with a standard track and moderate intensity."
    },
    {
      "name": "high_intensity_infusion",
      "input": ["track2.mp3", 70],
      "output": {"intensity": 70, "listenability": true},
      "args": ["track2.mp3", 70],
      "notes": "Tests high intensity infusion while maintaining listenability."
    },
    {
      "name": "low_intensity_infusion",
      "input": ["track3.mp3", 10],
      "output": {"intensity": 10, "listenability": true},
      "args": ["track3.mp3", 10],
      "notes": "Tests low intensity infusion to check for minimal impact."
    },
    {
      "name": "edge_case_silent_track",
      "input": ["silent_track.mp3", 50],
      "output": {"intensity": 0, "listenability": true},
      "args": ["silent_track.mp3", 50],
      "notes": "Tests behavior with a silent track; should not alter listenability."
    },
    {
      "name": "edge_case_noisy_track",
      "input": ["noisy_track.mp3", 50],
      "output": {"intensity": 50, "listenability": false},
      "args": ["noisy_track.mp3", 50],
      "notes": "Tests a noisy track to see if infusion is detectable."
    },
    {
      "name": "long_track_infusion",
      "input": ["long_track.mp3", 40],
      "output": {"intensity": 40, "listenability": true},
      "args": ["long_track.mp3", 40],
      "notes": "Tests infusion on a longer track to ensure consistency."
    },
    {
      "name": "multiple_tracks_infusion",
      "input": [["track1.mp3", "track2.mp3"], 50],
      "output": [{"intensity": 50, "listenability": true}, {"intensity": 50, "listenability": true}],
      "args": [["track1.mp3", "track2.mp3"], 50],
      "notes": "Tests infusion on multiple tracks simultaneously."
    },
    {
      "name": "invalid_track_format",
      "input": ["track_invalid.txt", 50],
      "output": {"error": "Invalid format"},
      "args": ["track_invalid.txt", 50],
      "notes": "Tests handling of unsupported file formats."
    }
  ],
  "assumptions": "Tracks are in MP3 format and accessible for processing.",
  "notes": "Ensure that the algorithm can handle various track lengths and qualities."
}
